<template>
    <div id="app" class="bg-plum text-white py-24">
        <div class="container mx-auto px-4 max-w-4xl">

            <!-- Step indicator -->
            <div class="border border-white/20 rounded-2xl p-8 md:p-12 mb-6">
                <div class="flex items-center gap-2 font-sans text-sm text-white/50">
                <span :class="current_step.number >= 1 ? 'text-white font-bold' : ''">1. Kaarten</span>
                <span class="text-white/30">›</span>
                <span :class="current_step.number >= 2 ? 'text-white font-bold' : ''">2. Gegevens</span>
                <span class="text-white/30">›</span>
                <span :class="current_step.number >= 3 ? 'text-white font-bold' : ''">3. Bevestiging</span>
            </div>
            </div>

            <!-- Step 1: Ticket selection -->
            <div v-if="current_step.number == 1" class="border border-white/20 rounded-2xl p-8 md:p-12">
