                <p class="text-center text-white/70 font-sans text-lg mb-10">Kies welke dag je wilt komen.</p>

                <!-- Ticket rows -->
                <div class="flex flex-col border-t border-white/20">
                    <!-- Header row -->
                    <div class="hidden md:flex items-center py-4 px-4 text-white/50 font-sans text-sm font-bold uppercase tracking-wider border-b border-white/20">
                        <div class="w-20">Aantal</div>
