                        <div class="w-40 text-right">Prijs</div>
                    </div>

                    <div v-for="ticket in tickets" class="ticket-row py-5 px-4 border-b border-white/20">
                        <div style="display:flex; align-items:center; gap:0.75rem; text-align:left;">
                            <!-- Amount select -->
                            <div style="flex-shrink:0;">
                                <select
                                    v-if="ticket.available"
                                    v-model="ticket.user_selected_amount"
                                    class="bg-white/10 border border-white/30 rounded-lg text-white font-sans focus:outline-none focus:border-magenta cursor-pointer"
                                    style="width:52px; padding:8px 4px; text-align:center;"
                                >
                                    <option value="0">0</option>
                                    <option value="1">1</option>
                                    <option value="2">2</option>
                                    <option value="3">3</option>
                                    <option value="4">4</option>
                                    <option value="5">5</option>
                                    <option value="6">6</option>
                                </select>
                                <select v-else disabled class="bg-white/5 border border-white/10 rounded-lg text-white/30 font-sans cursor-not-allowed" style="width:52px; padding:8px 4px; text-align:center;">
                                    <option value="0">0</option>
                                </select>
                            </div>

                            <!-- Name + description + (price on mobile) -->
                            <div style="flex:1; text-align:left;">
                                <div class="font-display font-bold text-white ticket-name" :class="!ticket.available ? 'opacity-40' : ''" style="word-break:keep-all; overflow-wrap:normal; font-size:1rem; text-align:left;">
                                    {{ ticket.name }}
                                </div>
                                <div v-if="!isMobile" class="font-sans text-white/50" style="font-size:0.78rem; margin-top:2px; text-align:left;" v-html="ticket.description ? ticket.description.replace(/\n/g, '<br>') : ''"></div>
                                <div v-if="!ticket.available" class="font-sans text-magenta font-bold" style="font-size:0.75rem; margin-top:2px; text-align:left;">Niet beschikbaar</div>
                                <!-- Price shown below name on mobile only -->
                                <div v-if="isMobile" :class="!ticket.available ? 'opacity-40' : ''" style="margin-top:4px; text-align:left;">
                                    <span class="font-display font-bold text-white" style="font-size:0.9rem;">&euro; {{ ticket.price }}</span>
                                    <span class="font-sans text-white/40" style="font-size:0.65rem; margin-left:4px;">+ &euro; {{ ticket.costs }} servicekosten</span>
                                </div>
                            </div>

                            <!-- Price on desktop -->
                            <div v-if="!isMobile" style="flex-shrink:0; text-align:right;" :class="!ticket.available ? 'opacity-40' : ''">
                                <div class="font-display font-bold text-white" style="font-size:1rem;">&euro; {{ ticket.price }}</div>
                                <div class="font-sans text-white/40" style="font-size:0.7rem; margin-top:2px; white-space:nowrap;">+ &euro; {{ ticket.costs }} servicekosten</div>
                            </div>
                        </div>
                    </div>
                </div>

                <!-- Error -->
                <div v-if="current_step.errors !== false" class="mt-6 rounded-xl bg-magenta/20 border border-magenta/50 px-5 py-4 text-white font-sans text-sm">
                    {{ current_step.errors }}
                </div>

                <!-- Next button -->
                <div class="mt-8 flex justify-end">
                    <button
                        v-on:click="validateStep1"
                        class="bg-magenta hover:opacity-90 transition-opacity text-white font-display font-bold text-lg px-8 py-4 rounded-xl cursor-pointer"
                    >
                        Vul je gegevens in →
                    </button>
                </div>
            </div>

            <!-- Step 2: Personal details -->
            <div v-if="current_step.number == 2" :style="isMobile ? 'display:flex; flex-direction:column; gap:1.5rem;' : 'display:flex; flex-direction:row; gap:1.5rem; align-items:flex-start;'">
                <div style="flex:1; min-width:0;" class="border border-white/20 rounded-2xl p-8">
                    <h1 class="font-display font-bold mb-10 tracking-tight text-white" :style="isMobile ? 'font-size:2rem;' : 'font-size:3.5rem;'">
                        Jouw gegevens
                    </h1>
                    <p class="text-white/70 font-sans mb-8" :style="isMobile ? 'font-size:1rem;' : 'font-size:1.125rem;'">We hebben een aantal gegevens van je nodig.</p>

                    <div class="flex flex-col gap-5">
                        <div>
                            <label class="block font-sans text-sm font-bold text-white/70 mb-2">Jouw e-mailadres</label>
                            <input type="email" v-model="user_info.email" placeholder="voorbeeld@email.nl"
                                class="w-full bg-white/10 border border-white/30 rounded-xl px-5 py-4 text-white placeholder-white/30 focus:outline-none focus:border-magenta font-sans text-lg transition-colors">
                        </div>
                        <div>
                            <label class="block font-sans text-sm font-bold text-white/70 mb-2">Bevestig jouw e-mailadres</label>
                            <input type="email" v-model="user_info.confirm_email" placeholder="voorbeeld@email.nl"
                                class="w-full bg-white/10 border border-white/30 rounded-xl px-5 py-4 text-white placeholder-white/30 focus:outline-none focus:border-magenta font-sans text-lg transition-colors">
                        </div>
                        <div>
                            <label class="block font-sans text-sm font-bold text-white/70 mb-2">Voornaam</label>
                            <input type="text" v-model="user_info.first_name" placeholder="Hier je voornaam"
                                class="w-full bg-white/10 border border-white/30 rounded-xl px-5 py-4 text-white placeholder-white/30 focus:outline-none focus:border-magenta font-sans text-lg transition-colors">
                        </div>
                        <div>
                            <label class="block font-sans text-sm font-bold text-white/70 mb-2">Achternaam</label>
                            <input type="text" v-model="user_info.last_name" placeholder="En hier je achternaam"
                                class="w-full bg-white/10 border border-white/30 rounded-xl px-5 py-4 text-white placeholder-white/30 focus:outline-none focus:border-magenta font-sans text-lg transition-colors">
                        </div>
                        <label class="flex items-start gap-3 font-sans text-sm text-white/70 cursor-pointer">
                            <input type="checkbox" v-model="user_info.news_letter_optin" class="mt-1 accent-magenta">
                            <span>Ja, ik wil ook de Loungefest nieuwsbrief ontvangen en geef toestemming aan de organisatie om mij e-mails te sturen.</span>
                        </label>
                        <label class="flex items-start gap-3 font-sans text-sm text-white/70 cursor-pointer">
                            <input type="checkbox" v-model="user_info.general_terms" class="mt-1 accent-magenta">
                            <span>Ik ga akkoord met de <a href="https://www.loungefest.nl/files/documenten/algemene-voorwaarden-stichting-nyce.pdf" class="text-magenta underline underline-offset-4 hover:opacity-80">Algemene Voorwaarden</a>.</span>
                        </label>
                    </div>

                    <!-- Error -->
                    <div v-if="current_step.errors !== false" class="mt-6 rounded-xl bg-magenta/20 border border-magenta/50 px-5 py-4 text-white font-sans text-sm">
                        {{ current_step.errors }}
                    </div>

                    <!-- Nav buttons -->
                    <div class="mt-8 flex justify-between items-center">
                        <button v-on:click="stepBack(1)" class="font-sans text-white/60 hover:text-white transition-colors cursor-pointer">
                            ← Terug
                        </button>
                        <button v-on:click="validateStep2" :disabled="loading"
                            class="bg-magenta hover:opacity-90 transition-opacity text-white font-display font-bold text-lg px-8 py-4 rounded-xl cursor-pointer"
                            style="display:inline-flex; align-items:center; gap:0.5rem; min-width:200px; justify-content:center;"
                            :style="loading ? 'opacity:0.7; cursor:not-allowed;' : ''">
                            <svg v-if="loading" style="animation:spin 0.8s linear infinite; width:1.2em; height:1.2em; flex-shrink:0;" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                                <circle cx="12" cy="12" r="10" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-dasharray="31.4 31.4" />
                            </svg>
                            <span>{{ loading ? 'Even geduld...' : 'Ga naar betalen →' }}</span>
                        </button>
                    </div>
                </div>

                <!-- Cart summary -->
                <div :style="isMobile ? 'width:100%; border:1px solid rgba(255,255,255,0.2); border-radius:1rem; padding:1.5rem;' : 'width:280px; flex-shrink:0; position:sticky; top:2rem; border:1px solid rgba(255,255,255,0.2); border-radius:1rem; padding:1.5rem;'">
                    <h3 class="font-display font-bold text-xl text-white mb-4">Jouw kaartjes</h3>
                    <div class="flex flex-col gap-3 text-white/80 text-sm">
                        <div v-for="ticket in selectedTickets" class="flex justify-between">
                            <span>{{ ticket.user_selected_amount }} × {{ ticket.name }}</span>
                            <span>&euro; {{ ticket.price + ticket.costs }}</span>
                        </div>
                        <div class="border-t border-white/20 pt-3 flex justify-between font-bold text-white text-base">
                            <span>Totaal</span>
                            <span>&euro; {{ totalPrice }}</span>
                        </div>
                    </div>
                    <button v-on:click="stepBack(1)" class="mt-4 text-xs text-white/40 hover:text-white/70 transition-colors cursor-pointer">
                        ← Kaarten aanpassen
                    </button>
                </div>
            </div>

            <!-- Step 3: Confirmation -->
            <div v-if="current_step.number == 3" class="border border-white/20 rounded-2xl p-8 md:p-12 text-center">
                <h1 class="font-display text-5xl sm:text-7xl font-bold mb-10 tracking-tight text-white">
                    Bevestiging
                </h1>
                <p class="text-white/70 font-sans text-lg">Overzicht van je bestelling.</p>
            </div>

        </div>
    </div>
</template>

<script>
    export default {
        name: 'app',
        data: function() {
            return {
                uid_counter: 0,
                event_id: 1,
                api_base_url: process.env.NODE_ENV === 'development' ? '/api/' : 'https://api.ticketchef.nl/',
                current_step: {},
                steps: [
                    {
                        number: 1,
                        name_clean: 'step_1',
                        valid: false,
                        errors: false
                    },
                    {
                        number: 2,
                        name_clean: 'step_2',
                        valid: false,
                        errors: false
                    },
                    {
                        number: 3,
                        name_clean: 'step_3',
                        valid: false,
                        errors: false
                    }
                ],
                tickets: [],
                user_info: {
                    email: '',
                    confirm_email: '',
                    first_name: '',
                    last_name: '',
                    city: '',
                    news_letter_optin: true,
                    general_terms: false
                },
                current_order: false,
                loading: false,
                isMobile: window.innerWidth < 600
            }
        },

        methods: {
            stepBack: function(index) {
                var self = this;
                self.current_step = self.steps[index - 1]
            },

            validateStep1: function() {
                var self = this;
                
                self.current_step.valid = true;

                if(self.selectedTickets < 1) {
                    self.current_step.valid = false;
                    self.current_step.errors = 'Hey, je moet wel meer dan 0 tickets bestellen...';
                }

                if(self.current_step.valid == true) {
                    $('.order-step2').fadeOut(100);
                    $('.order-step1').removeClass('in-active');
                    $('.order-step1').delay(100).fadeIn(100);
                    self.current_step = self.steps[1];
                }
            },

            validateStep2: function() {
                var self = this;

                self.current_step.valid = true;
                
                //All info entererd
                if (self.user_info.email == '' || self.user_info.confirm_email == '' || self.user_info.first_name == '' || self.user_info.last_name == '') {
                    self.current_step.valid = false;
                    self.current_step.errors = 'We missen nog wat gegevens van je...';
                }

                // E-mail address match
                if (self.current_step.valid == true && self.user_info.email != self.user_info.confirm_email) {
                    self.current_step.valid = false;
                    self.current_step.errors = 'Je e-mail adressen zijn niet het zelfde.';
                }

                //E-mail address valid
                var validRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9-]+(?:\.[a-zA-Z0-9-]+)*$/;
                if (!self.user_info.email.match(validRegex)) {
                  self.current_step.valid = false;
                  self.current_step.errors = 'Je e-mail adres is ongeldig.';
                }

                //accept general terms
                if (self.current_step.valid === true && self.user_info.general_terms === false) {
                    self.current_step.valid = false;
                    self.current_step.errors = 'U heeft de Algemene voorwaarden nog niet geaccepteerd.';
                }

                if(self.current_step.valid == true) {

                    self.loading = true;
                    var order = self.createOrder();
                    var url = self.api_base_url + 'order';

                    axios.post(url, order)
                        .then(function (response) {
                            if(response.status == 200 && response.data.status == 'OK') {
                                window.location.replace(response.data.paymentUrl);
                            } else {
                                self.loading = false;
                                alert('Er was een probleem met het aanmaken van de bestelling, probeer het later nogmaals.');
                            }    
                            
                        })
                        .catch(function (error) {
                            self.loading = false;
                            console.log(error);
                            alert('Er was een probleem met het aanmaken van de bestelling, probeer het later nogmaals.');
                        });
                }
            },


            //create order
            createOrder: function() {
                var self = this;

                var order_lines = [];

                _.each(self.selectedTickets, function(ticket) {
                    order_lines.push({
                        id: ticket.id,
                        quantity: ticket.user_selected_amount
                    });
                });

                var order = {
                    eventId: self.event_id,
                    orderItems: order_lines,
                    customer: {
                      name: self.user_info.first_name + ' ' + self.user_info.last_name,
                      email: self.user_info.email,
                      mailable: self.user_info.news_letter_optin
                    }
                };

                return order;
            },

            //create ticket object from fetched data
            createTicket: function(data) {
                var self = this;

                self.uid_counter = self.uid_counter + 1;

                var ticket = {
                    uid: self.uid_counter,
                    id: data.id,
                    name: data.name,
                    price: data.price,
                    costs: data.costs,
                    available: data.available,
                    description: data.description,
                    user_selected_amount: 0
                };

                return ticket;
            },

            //fetch available tickets from api
            getAvailableTickets: function() {
                var self = this;

                var ticketOrder = [
                    '21- Weekend',
                    'Vrijdag',
                    'Zaterdag Vroege vogel',
                    'Weekend Vroege vogel',
                    'Zaterdag Geluks vogel',
                    'Zaterdag Late vogel',
                    'Weekend Geluks vogel',
                    'Weekend Late vogel'
                ];

                //reset tickets
                self.tickets = [];

                var url = self.api_base_url + 'tickets/' + self.event_id;

                axios.get(url)
                    .then(function (response) {
                        if(response.status == 200 && response.data.length > 0) {
                            _.each(response.data, function(ticket_data) {
                                var ticket = self.createTicket(ticket_data);
                                self.tickets.push(ticket);
                            });
                            self.tickets.sort(function(a, b) {
                                var ai = ticketOrder.indexOf(a.name);
                                var bi = ticketOrder.indexOf(b.name);
                                if (ai === -1) ai = ticketOrder.length;
                                if (bi === -1) bi = ticketOrder.length;
                                return ai - bi;
                            });
                        } else {
                            alert('Er is een probleem bij het laden van de tickets, probeer het later nogmaals.');
                        }
                    })
                    .catch(function (error) {
                        console.log(error);
                        alert('Er is een probleem bij het laden van de tickets, probeer het later nogmaals.');
                    });
            }
        },

        computed: {
            selectedTickets: function() {
                var self = this;

                var selected_tickets = [];

                _.each(self.tickets, function(ticket) {
                    if(ticket.user_selected_amount > 0) {
                        selected_tickets.push(ticket);
                    }
                });

                return selected_tickets;
            },

            totalPrice: function () {
                var self = this;

                var price = 0;

                _.each(self.selectedTickets, function(ticket) {
                    price = price + ((ticket.price + ticket.costs) * ticket.user_selected_amount);
                });

                return price + 0.35;
            },
        },

        mounted() {
            var self = this;

            self.current_step = self.steps[0];
            self.getAvailableTickets();

            window.addEventListener('resize', function() {
                self.isMobile = window.innerWidth < 600;
            });
        }
    }
</script>

<style>
@keyframes spin {
    from { transform: rotate(0deg); }
    to   { transform: rotate(360deg); }
}

@media (min-width: 600px) {
    .ticket-name { font-size: 1.15rem !important; }
}

@media (max-width: 599px) {
    #app input[type=email],
    #app input[type=text] {
        padding: 10px 12px !important;
        font-size: 1rem !important;
    }
}
</style>

